const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

const SENDGRID_API_KEY = process.env.SENDGRID_API_KEY;
const TWILIO_ACCOUNT_SID = process.env.TWILIO_ACCOUNT_SID;
const TWILIO_AUTH_TOKEN = process.env.TWILIO_AUTH_TOKEN;
const TWILIO_PHONE_NUMBER = process.env.TWILIO_PHONE_NUMBER;

if (!SENDGRID_API_KEY || !TWILIO_ACCOUNT_SID || !TWILIO_AUTH_TOKEN || !TWILIO_PHONE_NUMBER) {
  throw new Error('Missing required environment variables for email and SMS services');
}

sgMail.setApiKey(SENDGRID_API_KEY);

const client = twilio(TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN);

exports.sendNotification = async (req, res) => {
  try {
    const { type, to, subject, text, html, message } = req.body;

    if (!type || !to) {
      return res.status(400).json({ error: 'Type and recipient are required' });
    }

    if (type === 'email') {
      if (!subject || (!text && !html)) {
        return res.status(400).json({ error: 'Subject and message content are required for email' });
      }

      const msg = {
        to,
        from: process.env.SENDGRID_FROM_EMAIL || 'noreply@yourapp.com',
        subject,
        text,
        html
      };

      await sgMail.send(msg);
    } else if (type === 'sms') {
      if (!message) {
        return res.status(400).json({ error: 'Message content is required for SMS' });
      }

      await client.messages.create({
        body: message,
        from: TWILIO_PHONE_NUMBER,
        to
      });
    } else {
      return res.status(400).json({ error: 'Invalid notification type. Use "email" or "sms"' });
    }

    res.status(200).json({ success: true, message: `Successfully sent ${type} to ${to}` });
  } catch (error) {
    console.error(`Error sending ${req.body.type || 'notification'}:`, error);
    
    if (error.code === 401) {
      return res.status(401).json({ error: 'Authentication failed' });
    }
    
    if (error.code === 400) {
      return res.status(400).json({ error: 'Invalid request parameters' });
    }
    
    res.status(500).json({ error: 'Failed to send notification' });
  }
};